data.content:
Use `MockHttpMessageHandler` to control responses, and leverage `CancellationToken` for timeout/cancellation tests:

```csharp
[TestClass]
public class DataFetcherTests
{
    // Helper: pluggable handler for HttpClient
    private sealed class MockHandler : HttpMessageHandler
    {
        private readonly Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> _send;
        public MockHandler(Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> send)
            => _send = send;
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken ct) => _send(request, ct);
    }

    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new MockHandler((_, _) =>
            Task.FromResult(new HttpResponseMessage(HttpStatusCode.OK)
            {
                Content = new StringContent("hello")
            }));

        var fetcher = new DataFetcher(new HttpClient(handler));

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_OnHttpError()
    {
        var handler = new MockHandler((_, _) =>
            Task.FromResult(new HttpResponseMessage(HttpStatusCode.InternalServerError)));

        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_Throws_WhenCancelled()
    {
        var handler = new MockHandler((_, ct) =>
        {
            ct.ThrowIfCancellationRequested();          // honour the token
            return Task.FromResult(new HttpResponseMessage(HttpStatusCode.OK));
        });

        using var cts = new CancellationTokenSource();
        cts.Cancel();                                    // pre-cancel

        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExceptionAsync<OperationCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    public async Task FetchAsync_Throws_OnTimeout()
    {
        var handler = new MockHandler(async (_, ct) =>
        {
            await Task.Delay(TimeSpan.FromSeconds(30), ct);   // simulate slow server
            return new HttpResponseMessage(HttpStatusCode.OK);
        });

        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)]   // MSTest-level safety net — fails if test hangs
    public async Task FetchAsync_CompletesWithinDeadline()
    {
        var handler = new MockHandler((_, _) =>
            Task.FromResult(new HttpResponseMessage(HttpStatusCode.OK)
            {
                Content = new StringContent("fast")
            }));

        var fetcher = new DataFetcher(new HttpClient(handler));

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("fast", result);
    }
}
```

**Key patterns:**

| Concern | Technique |
|---|---|
| **Mock HTTP** | Custom `HttpMessageHandler` — no external libs needed |
| **Cancellation** | Pre-cancel a `CancellationTokenSource`, assert `OperationCanceledException` |
| **Timeout** | Create `CancellationTokenSource(TimeSpan)`, mock a slow handler with `Task.Delay` |
| **Hung-test safety** | `[Timeout(ms)]` attribute as a guardrail on any async test |

`TaskCanceledException` inherits from `OperationCanceledException`, so both the cancellation and timeout tests catch the right exception family. The timeout test uses a real 50 ms deadline against a 30 s simulated delay, keeping CI fast.
